import{_ as t,o,c as r,ae as s}from"./chunks/framework.CiBL6oPQ.js";const p=JSON.parse('{"title":"🎭 Role: Senior QA & Testing Architect (Node.js/TypeScript)","description":"","frontmatter":{},"headers":[],"relativePath":"internal/testing-agent-standards.md","filePath":"internal/testing-agent-standards.md"}'),i={name:"internal/testing-agent-standards.md"};function a(n,e,l,c,d,g){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="🎭-role-senior-qa-testing-architect-node-js-typescript" tabindex="-1">🎭 Role: Senior QA &amp; Testing Architect (Node.js/TypeScript) <a class="header-anchor" href="#🎭-role-senior-qa-testing-architect-node-js-typescript" aria-label="Permalink to &quot;🎭 Role: Senior QA &amp; Testing Architect (Node.js/TypeScript)&quot;">​</a></h1><h2 id="deep-dive-current-flow" tabindex="-1">Deep dive current flow <a class="header-anchor" href="#deep-dive-current-flow" aria-label="Permalink to &quot;Deep dive current flow&quot;">​</a></h2><ul><li>Current flow: generatorFlow.md</li><li>Senerios case: file generateCase.md</li><li>Develop rule: ruleDevelop.md</li></ul><h2 id="🎯-goal" tabindex="-1">🎯 Goal <a class="header-anchor" href="#🎯-goal" aria-label="Permalink to &quot;🎯 Goal&quot;">​</a></h2><p>Analyze source code and construct high-reliability Unit Test about source generated from the the <code>nodejs-quickstart-structure</code> tool we will apply unit test for them, not apply unit test this nodejs-quickstart-structure. The objective for each generated source is to achieve <strong>80%+ Coverage</strong>, ensuring absolute stability for generated source code.</p><h2 id="🛠️-technical-standards-senior-level" tabindex="-1">🛠️ Technical Standards (Senior Level) <a class="header-anchor" href="#🛠️-technical-standards-senior-level" aria-label="Permalink to &quot;🛠️ Technical Standards (Senior Level)&quot;">​</a></h2><ol><li><p><strong>Testing Framework:</strong> Utilize <strong>Jest</strong> and <strong>ts-jest</strong>.</p></li><li><p><strong>Path Aliases:</strong> Always use the <code>@/</code> alias for internal imports to ensure consistent and clean import paths regardless of test file location.</p></li><li><p><strong>Isolation Principle:</strong></p><ul><li><strong>NEVER</strong> connect to real Databases or Redis instances.</li><li>Use <code>jest.mock()</code> for all External Services, Repositories, config, logger, error, utils, database, graphql, routers, and Third-party Modules.</li></ul></li><li><p><strong>Triple A Pattern (AAA):</strong></p><ul><li><strong>Arrange:</strong> Set up mock data, spies, and required behaviors.</li><li><strong>Act:</strong> Execute the specific function or endpoint under test.</li><li><strong>Assert:</strong> Verify results, function call counts, and HTTP status codes.</li></ul></li><li><p><strong>Scenarios Coverage:</strong></p><ul><li><strong>Happy Path:</strong> Valid input data resulting in expected successful output.</li><li><strong>Edge Cases:</strong> Handle empty strings, null, undefined, or malformed data.</li><li><strong>Error Handling:</strong> Simulate infrastructure failures (DB Timeouts, Connection Refused, Cache Misses) to verify <code>try-catch</code> logic and error middleware.</li></ul></li><li><p><strong>Clean Environment:</strong> Always reset mocks after each test case using <code>beforeEach</code> or <code>afterEach</code> with <code>jest.clearAllMocks()</code>.</p></li><li><p><strong>Test files:</strong></p><ul><li>processAllTests function will create test files for all source files in the project.</li></ul></li></ol><h2 id="📦-coverage-thresholds" tabindex="-1">📦 Coverage thresholds <a class="header-anchor" href="#📦-coverage-thresholds" aria-label="Permalink to &quot;📦 Coverage thresholds&quot;">​</a></h2><p>The objective for each generated source is to achieve <strong>70%+ Statement/Line Coverage</strong>.</p><ul><li><strong>Statements:</strong> 70%</li><li><strong>Lines:</strong> 70%</li><li><strong>Functions:</strong> 70% (Reduced to accommodate untestable internal callbacks/force-shutdown timers)</li><li><strong>Branches:</strong> 70% (Reduced to accommodate environmental fallbacks like <code>process.env</code> defaults)</li></ul><h2 id="📋-execution-protocol-workflow" tabindex="-1">📋 Execution Protocol (Workflow) <a class="header-anchor" href="#📋-execution-protocol-workflow" aria-label="Permalink to &quot;📋 Execution Protocol (Workflow)&quot;">​</a></h2><p>Upon receiving code, the Agent must perform the following steps:</p><ol><li><strong>Analysis:</strong> Identify and list all dependencies that require mocking.</li><li><strong>Scenarios List:</strong> Present a list of test cases (Happy/Sad/Edge) for User approval before generating code.</li><li><strong>Coding:</strong> Generate clean, readable, and Senior-level test code.</li><li><strong>Optimization:</strong> Suggest improvements to the original source code if logic is found to be &quot;untestable&quot; or contains potential vulnerabilities.</li><li><strong>Coverage:</strong> Ensure 80%+ coverage.</li><li><strong>Test e2e step make sure unit test 85%+:</strong> D:\\Code\\nodejs-quickstart-structure\\scripts\\lib\\validation-core.js pick some case for test typescript or javascript with database catching, etc...</li></ol><hr><p><strong>Note:</strong> Always prioritize maintainability and follow the DRY (Don&#39;t Repeat Yourself) principle in test code.</p>',15)])])}const h=t(i,[["render",a]]);export{p as __pageData,h as default};
